  const handleLogout = async () => {
    await supabase.auth.signOut();
    setAuthUser(null);
    setAuthRole(null);
    setProfileEmploymentStatus("active");
    setCurrentShift(null);
    setIsMenuOpen(false);
    setMenuPanel("main");
  };

  const liveSeconds = useMemo(() => {
    const shiftStart =
      visibleCurrentShift?.clockIn ||
      visibleCurrentShift?.date ||
      visibleCurrentShift?.createdAt ||
      visibleCurrentShift?.updatedAt ||
      null;
    if (!shiftStart) return 0;
    const tIn = parseStoredInstant(shiftStart).getTime();
    const tNow = now instanceof Date ? now.getTime() : new Date(now).getTime();
    if (!Number.isFinite(tIn) || !Number.isFinite(tNow)) return 0;
    const totalSeconds = Math.max(0, Math.floor((tNow - tIn) / 1000));
    let activeBreakSeconds = 0;
    if (visibleCurrentShift.breakStart && !visibleCurrentShift.breakEnd) {
      const tBreak = parseStoredInstant(visibleCurrentShift.breakStart).getTime();
      if (Number.isFinite(tBreak)) {
        activeBreakSeconds = Math.max(0, Math.floor((tNow - tBreak) / 1000));
      }
    }
    return Math.max(0, totalSeconds - activeBreakSeconds);
  }, [visibleCurrentShift, now]);

  const liveEarnings = (() => {
    if (!visibleCurrentShift) return 0;
    const rate = Number(visibleCurrentShift.hourlyRate ?? 0);
    const r = Number.isFinite(rate) ? rate : 0;
    const earned = (liveSeconds / 3600) * r;
    return Number.isFinite(earned) ? earned : 0;
  })();

  const createProjectTaskViaApi = async ({
    itemType,
    name,
    projectId: targetProjectId = "",
    projectName = "",
    specialProject = null,
    manualContract = null,
  }) => {
    if (!authUser?.id || !userCompany?.id) throw new Error("Company/user missing. Please logout and login again.");
    if (!canCreateProjectTaskFromClock) {
      throw new Error("Project/task creation is not available for this profile.");
    }
    const cleanName = String(name || "").trim();
    if (!cleanName) throw new Error(itemType === "task" ? "Task name is required." : "Project name is required.");
    try {
      const { response, json } = await fetchAuthedApiJson(getOperaApiUrl("/api/create-project-task"), {
        method: "POST",
        body: JSON.stringify({
          company_id: userCompany.id,
          item_type: itemType,
          name: cleanName,
          project_id: targetProjectId || null,
          project_name: projectName || "",
          special_project: specialProject || null,
          manual_contract: manualContract || null,
        }),
      });
      if (!response.ok || !json?.ok) {
        throw new Error(json?.error || "Project/task creation failed.");
      }
      return json;
    } catch (error) {
      if (isLocalOperaHost()) {
        console.warn("[PROJECT_TASK] API unavailable in local dev, using Supabase fallback", error);
        return createProjectTaskDirectly({
          itemType,
          name: cleanName,
          projectId: targetProjectId,
          projectName,
          specialProject,
          manualContract,
        });
      }
      throw error;
    }
  };

  const createClockProjectTask = async (itemType) => {
    const isTask = itemType === "task";
    if (!canCreateProjectTaskFromClock) {
      setLocationStatus(
        isTask
          ? "Project/task creation is not available for this profile."
          : "Project/task creation is not available for this profile."
      );
      setTimeout(() => setLocationStatus(""), 5000);
      return;
    }
    if (isTask && !clockSelectedProject) {
      setLocationStatus("Choose a project before adding a task.");
      setTimeout(() => setLocationStatus(""), 5000);
      return;
    }
    setClockCreateDraft({ open: true, itemType, name: "" });
    setClockCreateError("");
  };

  const submitClockCreateProjectTask = async (event) => {
    event?.preventDefault?.();
    const itemType = clockCreateDraft.itemType === "task" ? "task" : "project";
    const isTask = itemType === "task";
    const cleanName = String(clockCreateDraft.name || "").trim();
    if (!cleanName) {
      setClockCreateError(`${isTask ? "Task" : "Project"} name is required.`);
      return;
    }

    setClockCreateSaving(true);
    setClockCreateError("");
    const label = isTask ? "task" : "project";
    setLocationStatus(`Creating ${label}...`);
    try {
      const json = await createProjectTaskViaApi({
        itemType,
        name: cleanName,
        projectId: isTask ? clockSelectedProject?.id || projectId : "",
        projectName: isTask ? clockSelectedProject?.name || "" : "",
      });

      if (itemType === "project" && json?.project?.id) {
        const nextProject = { id: json.project.id, name: json.project.name || cleanName };
        setCompanyProjects((prev) => {
          const existing = (prev || []).filter((p) => String(p.id) !== String(nextProject.id));
          return [...existing, nextProject].sort((a, b) => String(a.name || "").localeCompare(String(b.name || "")));
        });
        const createdNames = (json.cost_centres || []).map((row) => row?.name).filter(Boolean);
        if (createdNames.length > 0) {
          setCostCentresByProjectId((prev) => ({
            ...prev,
            [String(nextProject.id)]: [...new Set([...(prev[String(nextProject.id)] || []), ...createdNames])].sort((a, b) => a.localeCompare(b)),
          }));
          setCostCenter(createdNames[0] || "");
        } else {
          setCostCenter("");
        }
        setProjectId(nextProject.id);
      } else if (itemType === "task") {
        const inserted = Array.isArray(json?.tasks) ? json.tasks : [];
        setCostCentresByProjectId((prev) => {
          const next = { ...prev };
          const selectedPid = String(clockSelectedProject?.id || projectId || "");
          const touchedProjectIds = inserted.length > 0
            ? inserted.map((row) => String(row.project_id || "")).filter(Boolean)
            : [selectedPid].filter(Boolean);
          for (const pid of touchedProjectIds) {
            const current = Array.isArray(next[pid]) ? next[pid] : [];
            next[pid] = [...new Set([...current, cleanName])].sort((a, b) => a.localeCompare(b));
          }
          return next;
        });
        setCostCenter(cleanName);
      }

      setClockSelectedScheduledTaskId("");
      setCompanyProjectsRefreshKey((key) => key + 1);
      setProjectsScreenRefreshKey((key) => key + 1);
      const status = json?.existed
        ? `${isTask ? "Task" : "Project"} already exists.`
        : `${isTask ? "Task" : "Project"} created.`;
      setClockCreateDraft({ open: false, itemType: "project", name: "" });
      setLocationStatus(status);
      setTimeout(() => setLocationStatus(""), 5000);
    } catch (err) {
      setClockCreateError(getErrorMessage(err));
      setLocationStatus(getErrorMessage(err));
      setTimeout(() => setLocationStatus(""), 7000);
    } finally {
      setClockCreateSaving(false);
    }
  };

  const handleProjectChange = (newProjectId) => {
    if (!newProjectId) {
      setProjectId("");
      setCostCenter("");
      return;
    }
    const nextProject =
      clockSelectableProjects.find((project) => String(project.id) === String(newProjectId));
    if (!nextProject) return;
    setProjectId(nextProject.id);
    setCostCenter("");
  };

  const openProjectManagementFromClock = useCallback(
    (mode = "project") => {
      setClockSelectedScheduledTaskId("");
      if (!canCreateProjectTaskFromClock) {
        setLocationStatus(
          mode === "costCentre"
            ? "Project/task creation is not available for this profile."
            : "Project/task creation is not available for this profile."
        );
        setTimeout(() => setLocationStatus(""), 5000);
        return;
      }
      setProjectsEditSuccess("");
      setProjectsAddSuccess("");
      setProjectsAddError("");
      setProjectEditError("");
      setAssignmentsSuccess("");
      setAssignmentsEditorError("");
      setProjectsListFilter("active");
      setMenuPanel("settings");
      setIsMenuOpen(false);
      if (mode === "project") {
        setEditingProjectId(null);
        setProjectEditDraft(null);
        setAssignmentsManageProjectId(null);
        setProjectsAddFormOpen(true);
        setProjectsTaskFormOpen(false);
      } else {
        setEditingProjectId(null);
        setProjectEditDraft(null);
        setAssignmentsManageProjectId(null);
        setProjectsAddFormOpen(false);
        setProjectsTaskFormOpen(true);
        setProjectsTaskProjectId(String(projectId || clockSelectedProject?.id || ""));
      }
      setActiveTab("projects");
    },
    [canCreateProjectTaskFromClock, clockSelectedProject?.id, projectId]
  );

  const notifyEmployeeProjectTaskCreated = async ({ itemType, itemName, projectName = "" }) => {
    if (isAdmin || !authUser?.id || !userCompany?.id) return;
    const cleanName = String(itemName || "").trim();
    if (!cleanName) return;
    const actorName = employeeDisplayName || authUser?.email || "Employee";
    const isTask = itemType === "task";
    try {
      await createCompanyNotifications(supabase, {
        companyId: userCompany.id,
        actorUserId: authUser.id,
        actorRole: userCompanyRole || "employee",
        type: isTask ? "task_created" : "project_created",
        title: isTask ? "New task created" : "New project created",
        message: isTask
          ? `New task created by ${actorName}: ${cleanName}${projectName ? `\nProject: ${projectName}` : ""}`
          : `New project created by ${actorName}: ${cleanName}`,
        projectName: projectName || (isTask ? "" : cleanName),
        costCentre: isTask ? cleanName : "",
      });
    } catch (err) {
      console.warn("[NOTIFY] employee project/task notification failed", err);
    }
  };

  const fetchCompanyDefaultCostCentreNames = async (companyId) => {
    const { data, error } = await supabase
      .from("cost_centres")
      .select("name")
      .eq("company_id", companyId)
      .eq("status", "active")
      .order("name", { ascending: true });
    if (error) throw error;
    const seen = new Set();
    const names = [];
    for (const row of data || []) {
      const name = String(row?.name || "").trim();
      const key = name.toLowerCase();
      if (!name || seen.has(key)) continue;
      seen.add(key);
      names.push(name);
    }
    return names;
  };

  const fetchActiveCompanyMemberUserIds = async (companyId) => {
    const { data: members, error: membersErr } = await supabase
      .from("company_members")
      .select("user_id")
      .eq("company_id", companyId);
    if (membersErr) throw membersErr;
    const userIds = [...new Set((members || []).map((m) => m.user_id).filter(Boolean))];
    if (userIds.length === 0) return [];

    const { data: profiles, error: profilesErr } = await supabase
      .from("profiles")
      .select("id, employment_status")
      .in("id", userIds);
    if (profilesErr) {
      console.warn("[PROJECT_DEFAULTS] profile status fetch failed", profilesErr);
      return userIds;
    }
    const statusById = Object.fromEntries((profiles || []).map((p) => [String(p.id), p.employment_status]));
    return userIds.filter((uid) => normalizeEmploymentStatus(statusById[String(uid)]) !== "archived");
  };

  const assignNewProjectToActiveMembers = async ({ companyId, projectId, costCentreRows, assignedBy }) => {
    const userIds = await fetchActiveCompanyMemberUserIds(companyId);
    if (userIds.length === 0) return { users: 0, costCentres: 0 };

    const projectAssignmentRows = userIds.map((uid) => ({
      company_id: companyId,
      project_id: projectId,
      user_id: uid,
      assigned_by: assignedBy,
      status: "active",
    }));

    const { error: paErr } = await supabase.from("project_assignments").insert(projectAssignmentRows);
    if (paErr) throw paErr;

    const activeCostCentres = (costCentreRows || []).filter((cc) => cc?.id);
    const pccaRows = [];
    for (const uid of userIds) {
      for (const cc of activeCostCentres) {
        pccaRows.push({
          company_id: companyId,
          project_id: projectId,
          cost_centre_id: cc.id,
          user_id: uid,
          assigned_by: assignedBy,
          status: "active",
        });
      }
    }

    if (pccaRows.length > 0) {
      const { error: pccaErr } = await supabase.from("project_cost_centre_assignments").insert(pccaRows);
      if (pccaErr) throw pccaErr;
    }

    return { users: userIds.length, costCentres: pccaRows.length };
  };

  const insertCompanyProjectWithCentres = async ({
    companyId,
    userId,
    projectName,
    costCentresCsv,
    assignCreatorWhenNotGlobal = false,
    specialProjectActive = false,
    specialHourlyRate = 0,
    specialProjectNotes = "",
  }) => {
    const name = String(projectName || "").trim();
    if (!name) {
      const err = new Error("Project name is required.");
      throw err;
    }
    const typedCentres = String(costCentresCsv || "")
      .split(",")
      .map((c) => c.trim())
      .filter(Boolean);
    const companyDefaultCentres = await fetchCompanyDefaultCostCentreNames(companyId);
    const centreSeen = new Set();
    const centres = [...companyDefaultCentres, ...typedCentres].filter((c) => {
      const key = String(c || "").trim().toLowerCase();
      if (!key || centreSeen.has(key)) return false;
      centreSeen.add(key);
      return true;
    });

    const projectPayload = {
      company_id: companyId,
      name,
      status: "active",
      created_by: userId,
      special_project_active: Boolean(specialProjectActive),
      special_hourly_rate: Number(specialHourlyRate ?? 0) || 0,
      special_project_notes: String(specialProjectNotes || "").trim(),
    };

    const { data: created, error: projectErr } = await supabase
      .from("projects")
      .insert([projectPayload])
      .select("id, name, status, special_project_active, special_hourly_rate, special_project_notes")
      .single();

    if (projectErr) throw projectErr;

    let createdCentres = [];
    if (centres.length > 0) {
      const rows = centres.map((c, index) => ({
        company_id: companyId,
        project_id: created.id,
        name: c,
        status: "active",
        display_order: index,
        created_by: userId,
      }));
      const { data: insertedCentres, error: centresErr } = await supabase
        .from("cost_centres")
        .insert(rows)
        .select("id, name");
      if (centresErr) throw centresErr;
      createdCentres = insertedCentres || [];
    }

    let assignments = { users: 0, costCentres: 0 };
    if (companyAssignAllProjectsToAllEmployees) {
      assignments = await assignNewProjectToActiveMembers({
        companyId,
        projectId: created.id,
        costCentreRows: companyAssignAllTasksToAllProjects ? createdCentres : [],
        assignedBy: userId,
      });
    } else if (assignCreatorWhenNotGlobal) {
      const { error: projectAssignErr } = await supabase.from("project_assignments").insert({
        company_id: companyId,
        project_id: created.id,
        user_id: userId,
        assigned_by: userId,
        status: "active",
      });
      if (projectAssignErr) throw projectAssignErr;

      const pccaRows = (createdCentres || [])
        .filter((cc) => cc?.id)
        .map((cc) => ({
          company_id: companyId,
          project_id: created.id,
          cost_centre_id: cc.id,
          user_id: userId,
          assigned_by: userId,
          status: "active",
        }));
      if (pccaRows.length > 0) {
        const { error: pccaErr } = await supabase.from("project_cost_centre_assignments").insert(pccaRows);
        if (pccaErr) throw pccaErr;
      }
      assignments = { users: 1, costCentres: pccaRows.length };
    }

    return { project: created, cost_centres: createdCentres, assignments };
  };

  const createProjectTaskDirectly = async ({
    itemType,
    name,
    projectId: targetProjectId = "",
    projectName = "",
    specialProject = null,
    manualContract = null,
  }) => {
    if (!authUser?.id || !userCompany?.id) throw new Error("Company/user missing. Please logout and login again.");
    if (!canCreateProjectTaskFromClock) throw new Error("Project/task creation is not available for this profile.");

    const cleanName = String(name || "").trim();
    if (!cleanName) throw new Error(itemType === "task" ? "Task name is required." : "Project name is required.");

    if (itemType === "project") {
      const specialProjectActive = Boolean(specialProject?.active);
      const specialHourlyRate = Number(specialProject?.specialHourlyRate ?? specialProject?.special_hourly_rate ?? 0) || 0;
      const specialProjectNotes = String(specialProject?.notes ?? specialProject?.special_project_notes ?? "").trim();
      const existing = (companyProjects || []).find(
        (project) => String(project?.name || "").trim().toLowerCase() === cleanName.toLowerCase()
      );
      if (existing?.id) {
        return {
          ok: true,
          item_type: "project",
          project: { id: existing.id, name: existing.name || cleanName, special_project_active: specialProjectActive, special_hourly_rate: specialHourlyRate, special_project_notes: specialProjectNotes },
          cost_centres: [],
          existed: true,
          assignments: { projects: 0, costCentres: 0 },
        };
      }

      const created = await insertCompanyProjectWithCentres({
        companyId: userCompany.id,
        userId: authUser.id,
        projectName: cleanName,
        costCentresCsv: "",
        assignCreatorWhenNotGlobal: !isAdmin,
        specialProjectActive,
        specialHourlyRate,
        specialProjectNotes,
      });
      if (!isAdmin) await notifyEmployeeProjectTaskCreated({ itemType: "project", itemName: cleanName });

      return {
        ok: true,
        item_type: "project",
        project: created.project,
        cost_centres: created.cost_centres || [],
        existed: false,
        assignments: {
          projects: created.assignments?.users || 0,
          costCentres: created.assignments?.costCentres || 0,
        },
      };
    }

    const manualContractFixedAmount = Number(manualContract?.fixedAmount ?? manualContract?.fixed_amount ?? 0) || 0;
    const manualContractNotes = String(manualContract?.notes ?? manualContract?.manual_contract_notes ?? "").trim();
    const manualContractActive = Boolean(manualContract?.active ?? manualContract?.manual_contract_active ?? manualContractFixedAmount > 0);
    const manualContractStartDate = String(manualContract?.startDate ?? manualContract?.manual_contract_start_date ?? "").trim();
    const manualContractEndDate = String(manualContract?.endDate ?? manualContract?.manual_contract_end_date ?? "").trim();
    const activeProjects = (companyProjects || []).filter((project) => project?.id != null);
    const targetProjectIds = companyAssignAllTasksToAllProjects
      ? activeProjects.map((project) => project.id).filter(Boolean)
      : [targetProjectId].filter(Boolean);

    if (targetProjectIds.length === 0) {
      throw new Error(companyAssignAllTasksToAllProjects ? "Add an active project before adding a task." : "Choose a project before adding a task.");
    }

    const { data: existingRows, error: existingError } = await supabase
      .from("cost_centres")
      .select("project_id, name, status")
      .eq("company_id", userCompany.id)
      .in("project_id", targetProjectIds);
    if (existingError) throw existingError;

    const wantedNameKey = cleanName.toLowerCase();
    const existingActive = new Set(
      (existingRows || [])
        .filter((row) => String(row?.status || "active").toLowerCase() !== "archived")
        .map((row) => `${String(row.project_id)}::${String(row.name || "").trim().toLowerCase()}`)
    );
    const rows = targetProjectIds
      .filter((pid) => !existingActive.has(`${String(pid)}::${wantedNameKey}`))
      .map((pid, index) => ({
        company_id: userCompany.id,
        project_id: pid,
        name: cleanName,
        status: "active",
        display_order: 1000 + index,
        created_by: authUser.id,
        manual_contract_active: manualContractActive,
        manual_contract_fixed_amount: manualContractFixedAmount,
        manual_contract_notes: manualContractNotes,
        manual_contract_start_date: manualContractStartDate || null,
        manual_contract_end_date: manualContractEndDate || null,
      }));

    let insertedTasks = [];
    if (rows.length > 0) {
      const { data: inserted, error: insertError } = await supabase
        .from("cost_centres")
        .insert(rows)
        .select("id, name, project_id");
      if (insertError) throw insertError;
      insertedTasks = inserted || [];
    }

    let assignedCount = 0;
    if (insertedTasks.length > 0) {
      const assignedUserIds = companyAssignAllProjectsToAllEmployees && companyAssignAllTasksToAllProjects
        ? await fetchActiveCompanyMemberUserIds(userCompany.id)
        : [authUser.id];
      const assignmentRows = [];
      for (const uid of assignedUserIds) {
        for (const task of insertedTasks) {
          if (!uid || !task?.id || !task?.project_id) continue;
          assignmentRows.push({
            company_id: userCompany.id,
            project_id: task.project_id,
            cost_centre_id: task.id,
            user_id: uid,
            assigned_by: authUser.id,
            status: "active",
          });
        }
      }
      if (assignmentRows.length > 0) {
        const { error: assignmentError } = await supabase.from("project_cost_centre_assignments").insert(assignmentRows);
        if (assignmentError) throw assignmentError;
        assignedCount = assignmentRows.length;
      }
    }

    if (!isAdmin && insertedTasks.length > 0) {
        const projectLabel =
          companyAssignAllTasksToAllProjects
            ? "All active projects"
            : projectName || companyProjects.find((project) => String(project.id) === String(targetProjectId))?.name || "";
        await notifyEmployeeProjectTaskCreated({ itemType: "task", itemName: cleanName, projectName: projectLabel });
      }

    return {
      ok: true,
      item_type: "task",
      tasks: insertedTasks,
      existed: insertedTasks.length === 0,
      assignments: { costCentres: assignedCount },
    };
  };

